```holoscript
object Door @pointable {
  geometry: 'model/door.glb'
  state: 'closed'
  isLocked: false

  states: {
    closed: { rotation: [0, 0, 0] }
    open: { rotation: [0, -90, 0] }
  }

  transition: {
    duration: 800
    easing: 'easeOutBack'
  }

  onPoint: {
    if (this.isLocked) {
      audio.play('locked')
      ui.showMessage('Door is locked')
    } else {
      this.state = this.state == 'closed' ? 'open' : 'closed'
      audio.play(this.state == 'open' ? 'door_open' : 'door_close')
    }
  }
}
```

```holoscript
object TriggerZone {
  geometry: 'box'
  size: [3, 2, 3]
  visible: false

  trigger: {
    layers: ['Player']
    once: true
  }

  onTriggerEnter(other): {
    if (other.tag == 'Player') {
