```holoscript
object Pistol @grabbable {
  geometry: 'model/pistol.glb'
  physics: { mass: 0.8 }

  stats: { damage: 15, fireRate: 300, projectileSpeed: 40, maxAmmo: 12 }
  ammo: 12
  lastFire: 0

  children: {
    transform muzzle { position: [0, 0.05, 0.15] }
  }

  onTrigger: {
    let now = Date.now()
    if (now - this.lastFire < this.stats.fireRate) return
    if (this.ammo <= 0) { audio.play('click_empty'); return }

    this.lastFire = now
    this.ammo--

    spawn(Bullet, {
      position: this.muzzle.worldPosition,
      velocity: this.muzzle.forward * this.stats.projectileSpeed,
      damage: this.stats.damage,
      owner: player.id
    })

    particles.spawn('muzzle_flash', this.muzzle.worldPosition)
    audio.play3d('pistol_fire', this.position)
    haptics.pulse('right', 0.4, 50)
  }
}

object Bullet {
  geometry: 'sphere'
  scale: 0.02
  material: { type: 'emissive', color: '#ffff00', emissiveIntensity: 2 }
  physics: { type: 'dynamic', mass: 0.01, continuous: true }
  lifetime: 2000

  onSpawn: { setTimeout(() => this.destroy(), this.lifetime) }

  onCollision(other): {
    if (other.id === this.owner) return
    if (other.health) other.takeDamage(this.damage)
    particles.spawn('bullet_impact', this.position)
    this.destroy()
  }
}
```

```holoscript
object HealthPickup @pointable @networked {
  geometry: 'model/health_pack.glb'
  position: [3, 0.5, 0]

  @networked active: true
  respawnTime: 15000

  animation float {
    property: 'position.y'
    from: 0.5
    to: 0.8
    duration: 1500
    loop: infinite
    easing: 'easeInOutSine'
  }

  children: {
    light Glow { type: 'point', color: '#22c55e', intensity: 0.8, range: 2 }
  }

  onPoint(player): {
    if (!this.active) return

    player.health = Math.min(player.health + 50, 100)
    this.active = false
    this.visible = false

    particles.spawn('heal_effect', player.position)
    audio.play3d('health_pickup', this.position)

    setTimeout(() => {
      this.active = true
      this.visible = true
      particles.spawn('respawn_sparkle', this.position)
    }, this.respawnTime)
  }
}
