```holoscript
controller GameManager @networked {
  @networked state: 'warmup'
  @networked scores: { red: 0, blue: 0 }
  @networked round: 1
  @networked timeRemaining: 0

  config: { warmupTime: 30000, roundTime: 300000, maxRounds: 3, scoreToWin: 50 }

  stateMachine GameState {
    initial: 'warmup'

    states: {
      warmup: {
        enter: {
          this.timeRemaining = this.config.warmupTime
          ui.showAll('warmupOverlay')
        }
        tick: { this.timeRemaining -= deltaTime }
        transitions: {
          ready: { when: () => this.timeRemaining <= 0, to: 'starting' }
        }
      }

      starting: {
        enter: { ui.countdown(3) }
        after: 3000 -> 'playing'
      }

      playing: {
        enter: {
          this.timeRemaining = this.config.roundTime
          audio.playGlobal('round_start')
        }
        tick: { this.timeRemaining -= deltaTime }
        transitions: {
          timeUp: { when: () => this.timeRemaining <= 0, to: 'roundEnd' }
          scoreWin: { when: () => this.checkScoreWin(), to: 'roundEnd' }
        }
      }

      roundEnd: {
        enter: {
          let winner = this.scores.red > this.scores.blue ? 'red' : 'blue'
          ui.showAll('roundEndOverlay', { winner })
        }
        after: 5000 -> {
          if (this.round >= this.config.maxRounds) return 'gameOver'
          this.round++
          return 'starting'
        }
      }

      gameOver: {
        enter: {
          let winner = this.scores.red > this.scores.blue ? 'Red Team' : 'Blue Team'
          ui.showAll('gameOverOverlay', { winner })
          audio.playGlobal('victory_fanfare')
        }
      }
    }
  }

  checkScoreWin(): {
    return this.scores.red >= this.config.scoreToWin || this.scores.blue >= this.config.scoreToWin
  }

  onPlayerKill(killer, victim): {
    if (killer.team) this.scores[killer.team]++
    ui.killfeed.add({ killer: killer.name, victim: victim.name })
  }
}
```

```holoscript
template PlayerAvatar @networked {
  geometry: 'model/player_rig.glb'

  @networked position
  @networked rotation
  @networked health: 100
  @networked shield: 50
  @networked team: null
  @networked state: 'alive'

  components: {
    health HealthSystem {
      max: 100
      regeneration: { rate: 5, delay: 5000 }

      onDamage(amount, source): {
        if (this.shield > 0) {
          let absorbed = Math.min(this.shield, amount * 0.7)
          this.shield -= absorbed
          amount -= absorbed
          particles.spawn('shield_hit', this.position)
        }

        this.health -= amount
        haptics.pulse(source.hand, 0.5, 100)

        if (this.health <= 0) this.die(source)
      }

      onHeal(amount): {
        this.health = Math.min(this.health + amount, this.max)
        particles.spawn('heal_effect', this.position)
      }
    }
  }

  stateMachine PlayerState {
    initial: 'alive'

    states: {
      alive: {
        enter: { this.visible = true; this.collidable = true }
        transitions: { die: 'dying' }
      }

      dying: {
        enter: {
          particles.spawn('death_explosion', this.position)
          audio.play3d('player_death', this.position)
        }
        after: 500 -> 'spectating'
      }

      spectating: {
        enter: {
          this.visible = false
          this.collidable = false
          camera.mode = 'freeFly'
        }
        transitions: { respawn: 'respawning' }
      }

      respawning: {
        enter: {
          let spawn = arena.getSpawnPoint(this.team)
          this.position = spawn.position
          this.health = 100
          this.shield = 50
          particles.spawn('respawn_effect', spawn.position)
        }
        after: 1000 -> 'alive'
      }
    }
  }

  children: {
    ui HealthBar {
      position: [0, 2.2, 0]
      billboard: true
      visible: (viewer) => viewer.id !== this.id
      bar: { current: () => this.health, max: 100 }
    }

    text PlayerName {
      position: [0, 2.4, 0]
      billboard: true
      content: () => this.displayName
      fontSize: 0.08
      color: () => teams[this.team]?.color || '#ffffff'
    }
  }
}
```

```holoscript
template Weapon @grabbable @networked {
  abstract: true

  @networked owner: null
  @networked ammo: 0
  @networked state: 'idle'

  physics: { mass: 0.8 }

  onGrab(player): {
    if (network.requestOwnership(this)) {
      this.owner = player.id
      player.equipped = this.id
      audio.play3d('weapon_pickup', this.position)
    }
  }

  onRelease: {
    this.owner = null
    if (player.equipped === this.id) player.equipped = null
  }

  stateMachine WeaponState {
    initial: 'idle'

    states: {
      idle: { transitions: { fire: 'firing' } }
      firing: {
        enter: { this.onFire() }
        after: () => this.fireRate -> 'cooldown'
      }
      cooldown: {
        after: () => this.cooldownTime -> 'idle'
      }
      reloading: {
        enter: { audio.play3d('reload', this.position) }
        after: () => this.reloadTime -> 'idle'
      }
    }
  }
}

object PlasmaPistol extends Weapon {
  geometry: 'model/plasma_pistol.glb'
  stats: { damage: 15, fireRate: 200, cooldownTime: 50, reloadTime: 1500, maxAmmo: 20, projectileSpeed: 50 }
  ammo: 20

  children: {
    transform muzzle { position: [0, 0.05, 0.3] }
  }

  onFire: {
    if (this.ammo <= 0) { this.state = 'reloading'; return }
    this.ammo--

    spawn(PlasmaProjectile, {
      position: this.muzzle.worldPosition,
      velocity: this.muzzle.forward * this.stats.projectileSpeed,
      owner: this.owner,
      damage: this.stats.damage
    })

    particles.spawn('muzzle_flash', this.muzzle.worldPosition)
    audio.play3d('plasma_fire', this.position)
    haptics.pulse(this.owner.hand, 0.3, 50)
  }
}

object QuantumRifle extends Weapon {
  geometry: 'model/quantum_rifle.glb'
  stats: { damage: 35, chargeTime: 500 }
  chargeLevel: 0

  children: {
    transform muzzle { position: [0, 0.08, 0.6] }
  }

  onFire: {
    if (this.chargeLevel < 1) {
      this.chargeLevel += deltaTime / this.stats.chargeTime
      haptics.continuous(this.owner.hand, this.chargeLevel * 0.5)
      return
    }

    this.chargeLevel = 0

    let hit = physics.raycast(this.muzzle.worldPosition, this.muzzle.forward, {
      maxDistance: 100,
      layers: ['players', 'environment'],
      ignore: [this.owner]
    })

    if (hit.entity?.health) {
      hit.entity.takeDamage(this.stats.damage, { source: this.owner })
      particles.spawn('quantum_impact', hit.point)
    }

    audio.play3d('quantum_fire', this.position)
    haptics.pulse(this.owner.hand, 0.8, 150)
  }
}
```

```holoscript
ui GameHUD {
  anchor: 'screen'
  visible: () => game.state === 'playing'

  children: {
    group TopBar {
      position: [0.5, 0.95, 0]
      anchor: 'top-center'

      text Timer {
