```holoscript
object TeleportPad @pointable {
  geometry: 'cylinder'
  position: [0, 0.05, 0]
  scale: [1.5, 0.1, 1.5]
  color: '#8b5cf6'

  destination: [20, 0, 20]

  children: {
    particles TeleportRing {
      emitter: 'ring'
      radius: 1.5
      emission: { rate: 30 }
      particle: {
