object GuardNPC @networked @collidable {
  model: 'guard.glb'
  position: [0, 0, 0]
  scale: 1

  state patrolIndex: 0
  state isGreeting: false

  const patrolPoints: [
    [0, 0, 0],
    [5, 0, 0],
    [5, 0, 5],
    [0, 0, 5]
  ]

  animation Walk {
    clip: 'walk'
    loop: true
  }

  animation Idle {
    clip: 'idle'
    loop: true
  }

  animation Wave {
    clip: 'wave'
    loop: false
  }

  // Patrol behavior
  on interval 3s {
    if not isGreeting {
      set patrolIndex: (patrolIndex + 1) % 4
      let target: patrolPoints[patrolIndex]

      look at target
      play Walk
      animate position to target duration: 2.5s easing: 'linear'
    }
  }

  // Greeting trigger zone
  trigger GreetingZone {
    shape: 'sphere'
    radius: 3

    on enter by player {
      if not isGreeting {
        set isGreeting: true
        stop animation Walk
        look at player
        play Wave

        speech Greeting {
          text: 'Hello there, traveler!'
          duration: 3s
          style: { bubble: true, color: '#FFFFFF' }
        }

        after 3s {
          set isGreeting: false
          play Walk
        }
      }
    }
  }
}
