  // Objects can be sent between dream spaces

  state dreamPortals: []

  // Personal dream bubble
  object MyDreamBubble {
    geometry: 'sphere'
    position: [0, 2, 0]
    scale: 3
    color: '#8844FF'
    opacity: 0.2

    // Only visible to owner
    visibility: 'owner'
  }

