    }

    // Armor
    leather_helm: {
      name: 'Leather Helm'
      type: 'armor'
      slot: 'head'
      stackable: false
      rarity: 'common'
      stats: { defense: 5 }
      icon: 'icons/leather_helm.png'
      sellValue: 15
    }
    dragon_plate: {
      name: 'Dragon Plate'
      type: 'armor'
      slot: 'chest'
      stackable: false
      rarity: 'legendary'
      stats: { defense: 50, fireResist: 30, health: 100 }
      icon: 'icons/dragon_plate.png'
      sellValue: 2000
    }

    // Consumables
    health_potion: {
      name: 'Health Potion'
      type: 'consumable'
      stackable: true
      maxStack: 20
      rarity: 'common'
      effect: { heal: 50 }
      icon: 'icons/health_potion.png'
      sellValue: 10
    }
    mana_potion: {
      name: 'Mana Potion'
      type: 'consumable'
      stackable: true
      maxStack: 20
      rarity: 'common'
      effect: { mana: 50 }
      icon: 'icons/mana_potion.png'
      sellValue: 10
    }

    // Materials
    iron_ore: {
      name: 'Iron Ore'
      type: 'material'
      stackable: true
      maxStack: 99
      rarity: 'common'
      icon: 'icons/iron_ore.png'
      sellValue: 5
    }
    dragon_scale: {
      name: 'Dragon Scale'
      type: 'material'
      stackable: true
      maxStack: 50
      rarity: 'epic'
      icon: 'icons/dragon_scale.png'
      sellValue: 100
    }
  }

  const RECIPES: {
    iron_sword: {
      materials: { iron_ore: 5 }
      result: { item: 'iron_sword', count: 1 }
      craftTime: 2
    }
    health_potion: {
      materials: { herb: 2, water: 1 }
      result: { item: 'health_potion', count: 3 }
      craftTime: 1
    }
    dragon_plate: {
      materials: { dragon_scale: 10, iron_ore: 20, fire_essence: 5 }
      result: { item: 'dragon_plate', count: 1 }
      craftTime: 10
    }
  }

  // ==========================================
  // PLAYER INVENTORY STATE
  // ==========================================

  state inventory: []  // Array of { itemId, count, slotIndex }
  state equipment: {
    head: null
    chest: null
    hands: null
    feet: null
    weapon: null
  }
  state gold: 100
  state inventorySize: 24

  state draggedItem: null
  state draggedFrom: null
  state showTooltip: false
  state tooltipItem: null
  state tooltipPosition: [0, 0]

  // ==========================================
  // INVENTORY FUNCTIONS
  // ==========================================

  function addItem(itemId, count: 1) {
    let itemDef: ITEM_DATABASE[itemId]

    if itemDef.stackable {
      // Find existing stack
      let existing: inventory.find(i => i.itemId == itemId and i.count < itemDef.maxStack)

      if existing {
        let space: itemDef.maxStack - existing.count
        let toAdd: min(count, space)
        set existing.count: existing.count + toAdd
        count -= toAdd
      }
    }

    // Add new stacks
    while count > 0 {
      let emptySlot: findEmptySlot()
      if emptySlot == -1 {
        notify player 'Inventory full!'
        return false
      }

      let stackSize: itemDef.stackable ? min(count, itemDef.maxStack) : 1
      push { itemId: itemId, count: stackSize, slotIndex: emptySlot } to inventory
      count -= stackSize
    }

    play sound 'item_pickup.mp3'
    return true
  }

  function removeItem(itemId, count: 1) {
    let remaining: count

    for slot in inventory.filter(i => i.itemId == itemId).reverse() {
      if remaining <= 0 { break }

      if slot.count <= remaining {
        remaining -= slot.count
        remove slot from inventory
      } else {
        set slot.count: slot.count - remaining
        remaining = 0
      }
    }

    return remaining == 0
  }

  function getItemCount(itemId) {
    return inventory
      .filter(i => i.itemId == itemId)
      .reduce((sum, i) => sum + i.count, 0)
  }

  function findEmptySlot() {
    repeat inventorySize as i {
      if not inventory.find(item => item.slotIndex == i) {
        return i
      }
    }
    return -1
  }

  function equipItem(slot) {
    let item: inventory.find(i => i.slotIndex == slot.slotIndex)
    if not item { return }

    let itemDef: ITEM_DATABASE[item.itemId]
    if not itemDef.slot { return }  // Can't equip non-equipment

    let targetSlot: itemDef.slot

    // Swap with currently equipped
    let currentEquip: equipment[targetSlot]
    if currentEquip {
      set item.itemId: currentEquip
      set item.count: 1
    } else {
      remove item from inventory
    }

    set equipment[targetSlot]: item.itemId

    call recalculateStats()
    play sound 'equip.mp3'
  }

  function unequipItem(slotName) {
    let itemId: equipment[slotName]
    if not itemId { return }

    if not addItem(itemId, 1) {
      notify player 'Inventory full!'
      return
    }

    set equipment[slotName]: null
    call recalculateStats()
  }

  function recalculateStats() {
    let totalStats: { damage: 0, defense: 0, health: 0, speed: 1 }

    for slotName in ['head', 'chest', 'hands', 'feet', 'weapon'] {
      let itemId: equipment[slotName]
      if itemId {
        let itemDef: ITEM_DATABASE[itemId]
        let rarity: RARITIES[itemDef.rarity]

        for stat in Object.keys(itemDef.stats) {
          totalStats[stat] += itemDef.stats[stat] * rarity.multiplier
        }
      }
    }

    set player.bonusStats: totalStats
  }

  function useItem(slot) {
    let item: inventory.find(i => i.slotIndex == slot.slotIndex)
    if not item { return }

    let itemDef: ITEM_DATABASE[item.itemId]

    if itemDef.type == 'consumable' {
      // Apply effect
      if itemDef.effect.heal {
        set player.health: min(player.health + itemDef.effect.heal, player.maxHealth)
        notify player '+{itemDef.effect.heal} Health'
      }
      if itemDef.effect.mana {
        set player.mana: min(player.mana + itemDef.effect.mana, player.maxMana)
        notify player '+{itemDef.effect.mana} Mana'
      }

      // Remove one from stack
      set item.count: item.count - 1
      if item.count <= 0 {
        remove item from inventory
      }

      play sound 'consume.mp3'
    } else if itemDef.slot {
      call equipItem(slot)
    }
  }

  function sellItem(slotIndex, count: 1) {
    let item: inventory.find(i => i.slotIndex == slotIndex)
    if not item { return }

    let itemDef: ITEM_DATABASE[item.itemId]
    let sellCount: min(count, item.count)
    let earnings: sellCount * itemDef.sellValue

    set item.count: item.count - sellCount
    if item.count <= 0 {
      remove item from inventory
    }

    set gold: gold + earnings

    notify player 'Sold for {earnings} gold'
    play sound 'coin.mp3'
  }

  function canCraft(recipeId) {
    let recipe: RECIPES[recipeId]
    if not recipe { return false }

    for material in Object.keys(recipe.materials) {
      if getItemCount(material) < recipe.materials[material] {
        return false
      }
    }
    return true
  }

  function craftItem(recipeId) {
    let recipe: RECIPES[recipeId]

    if not canCraft(recipeId) {
      notify player 'Missing materials!'
      return
    }

    // Remove materials
    for material in Object.keys(recipe.materials) {
      removeItem(material, recipe.materials[material])
    }

    // Add result
    addItem(recipe.result.item, recipe.result.count)

    notify player 'Crafted {ITEM_DATABASE[recipe.result.item].name}!'
    play sound 'craft.mp3'
  }

  // ==========================================
  // INVENTORY UI
  // ==========================================

  ui InventoryPanel {
