    for reward in node.rewards {
      switch reward.type {
        case 'item':
          addItem(reward.id, reward.count)
          break
        case 'gold':
          set gold: gold + reward.amount
          break
        case 'reputation':
          set reputation[reward.faction]: reputation[reward.faction] + reward.amount
          break
      }
    }

    // Move quest to completed
    let quest: activeQuests.find(q => q.id == currentNode.questId)
    remove quest from activeQuests
    push quest.id to completedQuests

    notify player 'Quest Complete!'
    play sound 'quest_complete.mp3'
  }

